def play_game():
    secret = random.randint(1, 10)
    guesses = [3, 7, 5, secret]
    for guess in guesses:
        if guess == secret:
            print("Guess", guess, "-> you win! 🎉")
        elif guess < secret:
            print("Guess", guess, "-> too low")
        else:
            print("Guess", guess, "-> too high")

